const raw = $input.first().json;
const body = raw.body || raw;

let chatId = 'unknown';
let text = '';
let firstName = '';
let lastName = '';
let username = '';
let callbackQueryId = null;
let isCallback = false;

if (body.message) {
  chatId    = String(body.message.chat.id);
  text      = (body.message.text || '').trim();
  firstName = body.message.from.first_name || '';
  lastName  = body.message.from.last_name || '';
  username  = body.message.from.username || '';

} else if (body.callback_query) {
  chatId          = String(body.callback_query.message.chat.id);
  text            = body.callback_query.data || '';
  firstName       = body.callback_query.from.first_name || '';
  lastName        = body.callback_query.from.last_name || '';
  username        = body.callback_query.from.username || '';
  callbackQueryId = body.callback_query.id;
  isCallback      = true;
}

const guestName = (firstName + ' ' + lastName).trim() || username || 'Guest';

return [{
  json: {
    chatId,
    text,
    guestName,
    username,
    callbackQueryId,
    isCallback,
    timestamp: new Date().toISOString()
  }
}];

const tgData = $('Parse Telegram Payload').first().json;
const sessionRows = $input.all();

// Check if session exists
let session = null;
if (sessionRows.length > 0 && sessionRows[0].json.chat_id) {
  const row = sessionRows[0].json;
  session = {
    chatId:    row.chat_id,
    step:      row.step || 'start',
    guestName: row.guest_name || tgData.guestName,
    checkin:   row.checkin || '',
    checkout:  row.checkout || '',
    roomPref:  row.room_pref || '',
    guests:    row.guests || '',
    email:     row.email || '',
    intent:    row.intent || ''
  };
} else {
  // New session
  session = {
    chatId:    tgData.chatId,
    step:      'start',
    guestName: tgData.guestName,
    checkin:   '',
    checkout:  '',
    roomPref:  '',
    guests:    '',
    email:     '',
    intent:    ''
  };
}

return [{
  json: {
    ...tgData,
    session,
    isNewSession: !sessionRows[0]?.json?.chat_id
  }
}];

const data = $input.first().json;
const { session } = data;

const text = (data.text || '').trim();
const lowerText = text.toLowerCase();
const step = session.step;

let replyText = '';
let replyMarkup = null;
let nextStep = step;
let updateSession = { ...session };

const mainMenu = {
  inline_keyboard: [
    [{ text: '🛏 Room Booking', callback_data: 'intent_booking' }],
    [{ text: '🍽 Room Service', callback_data: 'intent_roomservice' }],
    [{ text: '❓ FAQ / Info', callback_data: 'intent_faq' }],
    [{ text: '📞 Other / Talk to Staff', callback_data: 'intent_other' }]
  ]
};

// ============================================================
// STEP MACHINE — urut dari atas, STOP di match pertama
// ============================================================

// /start atau pesan pertama (step masih 'start')
if (step === 'start' || text === '/start' || text === '/menu') {
  replyText = `🏨 Welcome to *Hotel Adriatica*, ${session.guestName}!\n\nWhere the sea meets serenity — Shkodër, Albania 🌊\n\nHow can I assist you today?`;
  replyMarkup = mainMenu;
  nextStep = 'awaiting_intent';

// Guest sudah di awaiting_intent — proses pilihan
} else if (step === 'awaiting_intent') {

  if (text.startsWith('intent_')) {
    const choice = text.replace('intent_', '');
    if (choice === 'booking' || choice === 'start' === false && choice === 'booking') {
      replyText = '🛏 *Room Booking*\n\nPlease enter your *check-in date*\n_(format: DD Mon, e.g. 20 Jun)_';
      nextStep = 'awaiting_checkin';
      updateSession.intent = 'booking';
    } else if (choice === 'roomservice') {
      replyText = '🍽 *Room Service*\n\nPlease describe what you would like to order:';
      nextStep = 'awaiting_roomservice_detail';
      updateSession.intent = 'room_service';
    } else if (choice === 'faq') {
      replyText = '❓ *What would you like to know?*';
      replyMarkup = {
        inline_keyboard: [
          [{ text: '🏊 Pool & Facilities', callback_data: 'faq_facilities' }],
          [{ text: '🕐 Check-in / Check-out', callback_data: 'faq_checkinout' }],
          [{ text: '🚗 Parking & Transport', callback_data: 'faq_transport' }],
          [{ text: '🍳 Restaurant Hours', callback_data: 'faq_restaurant' }],
          [{ text: '📶 WiFi Info', callback_data: 'faq_wifi' }],
          [{ text: '↩️ Back to Menu', callback_data: 'intent_start' }]
        ]
      };
      nextStep = 'awaiting_faq';
      updateSession.intent = 'faq';
    } else if (choice === 'other') {
      replyText = '📞 Please describe your request and our team will assist you shortly:';
      nextStep = 'awaiting_other_detail';
      updateSession.intent = 'other';
    } else if (choice === 'start') {
      replyText = '🏨 *Hotel Adriatica* — Main Menu\n\nHow can I assist you?';
      replyMarkup = mainMenu;
      nextStep = 'awaiting_intent';
    }

  } else {
    // Free text — deteksi intent dari kata kunci
    if (lowerText.includes('book') || lowerText.includes('reservation') || lowerText.includes('room') || lowerText.includes('stay') || lowerText.includes('night')) {
      replyText = '🛏 *Room Booking*\n\nPlease enter your *check-in date*\n_(format: DD Mon, e.g. 20 Jun)_';
      nextStep = 'awaiting_checkin';
      updateSession.intent = 'booking';
    } else if (lowerText.includes('food') || lowerText.includes('eat') || lowerText.includes('order') || lowerText.includes('service') || lowerText.includes('drink')) {
      replyText = '🍽 *Room Service*\n\nPlease describe what you would like to order:';
      nextStep = 'awaiting_roomservice_detail';
      updateSession.intent = 'room_service';
    } else if (lowerText.includes('wifi') || lowerText.includes('pool') || lowerText.includes('check') || lowerText.includes('parking') || lowerText.includes('restaurant') || lowerText.includes('info') || lowerText.includes('faq')) {
      replyText = '❓ *What would you like to know?*';
      replyMarkup = {
        inline_keyboard: [
          [{ text: '🏊 Pool & Facilities', callback_data: 'faq_facilities' }],
          [{ text: '🕐 Check-in / Check-out', callback_data: 'faq_checkinout' }],
          [{ text: '🚗 Parking & Transport', callback_data: 'faq_transport' }],
          [{ text: '🍳 Restaurant Hours', callback_data: 'faq_restaurant' }],
          [{ text: '📶 WiFi Info', callback_data: 'faq_wifi' }]
        ]
      };
      nextStep = 'awaiting_faq';
      updateSession.intent = 'faq';
    } else if (lowerText.includes('hi') || lowerText.includes('hello') || lowerText.includes('halo') || lowerText.includes('hey') || lowerText.includes('good')) {
      replyText = `Hello ${session.guestName}! 👋\n\nHow can I assist you today?`;
      replyMarkup = mainMenu;
      nextStep = 'awaiting_intent';
    } else {
      replyText = 'I\'m here to help! What would you like to do?';
      replyMarkup = mainMenu;
      nextStep = 'awaiting_intent';
    }
  }

} else if (step === 'awaiting_checkin') {
  updateSession.checkin = text;
  replyText = `✅ Check-in: *${text}*\n\nNow please enter your *check-out date*:`;
  nextStep = 'awaiting_checkout';

} else if (step === 'awaiting_checkout') {
  updateSession.checkout = text;
  replyText = `✅ Check-out: *${text}*\n\nHow many guests? _(1–4)_`;
  nextStep = 'awaiting_guests';

} else if (step === 'awaiting_guests') {
  updateSession.guests = text;
  replyText = '✅ Got it!\n\nWhich room type do you prefer?';
  replyMarkup = {
    inline_keyboard: [
      [{ text: '🛏 Standard — €85/night', callback_data: 'room_standard' }],
      [{ text: '🌊 Superior Sea View — €120/night', callback_data: 'room_superior' }],
      [{ text: '🌅 Deluxe Balcony — €155/night', callback_data: 'room_deluxe' }],
      [{ text: '👑 Junior Suite — €200/night', callback_data: 'room_junior_suite' }],
      [{ text: '✨ Penthouse Suite — €320/night', callback_data: 'room_penthouse' }],
      [{ text: '🤷 No preference', callback_data: 'room_any' }]
    ]
  };
  nextStep = 'awaiting_roomtype';

} else if (step === 'awaiting_roomtype' || text.startsWith('room_')) {
  const roomMap = {
    'room_standard':     'Standard Room (€85/night)',
    'room_superior':     'Superior Sea View (€120/night)',
    'room_deluxe':       'Deluxe Balcony (€155/night)',
    'room_junior_suite': 'Junior Suite (€200/night)',
    'room_penthouse':    'Penthouse Suite (€320/night)',
    'room_any':          'No preference'
  };
  updateSession.roomPref = roomMap[text] || text;
  replyText = `✅ Room: *${updateSession.roomPref}*\n\nPlease share your *email address* for booking confirmation:`;
  nextStep = 'awaiting_email';

} else if (step === 'awaiting_email') {
  updateSession.email = text;
  const s = updateSession;
  replyText = `📋 *Booking Summary*\n\n` +
    `👤 Name: ${s.guestName}\n` +
    `📅 Check-in: ${s.checkin}\n` +
    `📅 Check-out: ${s.checkout}\n` +
    `👥 Guests: ${s.guests}\n` +
    `🛏 Room: ${s.roomPref}\n` +
    `📧 Email: ${s.email}\n\n` +
    `Shall I confirm this booking?`;
  replyMarkup = {
    inline_keyboard: [
      [{ text: '✅ Yes, confirm!', callback_data: 'confirm_yes' }],
      [{ text: '✏️ Edit booking', callback_data: 'confirm_edit' }],
      [{ text: '❌ Cancel', callback_data: 'confirm_cancel' }]
    ]
  };
  nextStep = 'awaiting_confirmation';

} else if (step === 'awaiting_confirmation') {
  if (text === 'confirm_yes') {
    replyText = `🎉 *Booking Confirmed!*\n\nThank you, ${session.guestName}!\n\nYour reservation has been received. A confirmation email will be sent to *${updateSession.email || session.email}*.\n\n📞 +355 22 123 456\n🌐 concierge@adriatica-hotel.com\n\nWe look forward to welcoming you! 🏨`;
    nextStep = 'done';
    updateSession.intent = 'confirmed_booking';
  } else if (text === 'confirm_edit') {
    replyText = 'No problem! Please enter your *check-in date*:';
    nextStep = 'awaiting_checkin';
    updateSession.checkin = '';
    updateSession.checkout = '';
    updateSession.roomPref = '';
    updateSession.guests = '';
  } else if (text === 'confirm_cancel') {
    replyText = '❌ Booking cancelled. Anything else I can help with?';
    replyMarkup = { inline_keyboard: [[{ text: '↩️ Back to Menu', callback_data: 'intent_start' }]] };
    nextStep = 'start';
  }

} else if (step === 'awaiting_faq') {
  const faqMap = {
    'faq_facilities': '🏊 *Pool & Facilities*\n\nOutdoor infinity pool: 08:00–20:00 (heated May–Oct)\nSpa & Wellness: 09:00–21:00\nFitness Center: 06:00–22:00\nPrivate beach: 200m from hotel (free for guests)',
    'faq_checkinout': '🕐 *Check-in & Check-out*\n\nCheck-in: 14:00\nCheck-out: 11:00\nEarly check-in: €30/hour\nLate check-out: €25/hour\nLuggage storage: Free',
    'faq_transport':  '🚗 *Parking & Transport*\n\nFree parking: 30 spaces\nAirport transfer (TIA): €60 one-way\nMust book 24h in advance',
    'faq_restaurant': '🍳 *Restaurant Mare Blu*\n\nBreakfast: 07:00–10:30\nLunch: 12:00–15:00\nDinner: 18:00–23:00\nRooftop Bar "Adriatic Sky": 17:00–01:00',
    'faq_wifi':       '📶 *WiFi*\n\nNetwork: ADRIATICA_GUEST\nPassword: SeaBreeze2024\nSpeed: 100 Mbps — Free throughout hotel'
  };
  replyText = faqMap[text] || 'Please select a topic from the menu above.';
  if (faqMap[text]) {
    replyText += '\n\nAnything else I can help you with?';
    replyMarkup = { inline_keyboard: [[{ text: '❓ More FAQ', callback_data: 'intent_faq' }],[{ text: '↩️ Main Menu', callback_data: 'intent_start' }]] };
  }
  nextStep = 'awaiting_faq';

} else if (step === 'awaiting_roomservice_detail') {
  replyText = `✅ Order received:\n\n_"${text}"_\n\nEstimated delivery: 25 minutes. Is there anything else?`;
  replyMarkup = { inline_keyboard: [[{ text: '↩️ Main Menu', callback_data: 'intent_start' }]] };
  nextStep = 'start';

} else if (step === 'awaiting_other_detail') {
  replyText = `✅ Message forwarded to our concierge team:\n\n_"${text}"_\n\nWe will respond as soon as possible. Thank you! 🙏`;
  replyMarkup = { inline_keyboard: [[{ text: '↩️ Main Menu', callback_data: 'intent_start' }]] };
  nextStep = 'start';

} else {
  replyText = 'I\'m here to help! What would you like to do?';
  replyMarkup = mainMenu;
  nextStep = 'awaiting_intent';
}

updateSession.step = nextStep;

return [{
  json: {
    ...data,
    session: updateSession,
    replyText,
    replyMarkup,
    nextStep
  }
}];
